export * from './switch.base';
export * from './switch-card.component';
export * from './switch.component';
export * from './switch.variants';
export * from './switch.imports';

import {
  booleanAttribute,
  ChangeDetectionStrategy,
  Component,
  computed,
  forwardRef,
  input,
  ViewEncapsulation,
} from '@angular/core';
import { NG_VALUE_ACCESSOR } from '@angular/forms';
import { NgIcon } from '@ng-icons/core';

import { cn } from '{{alias}}/utils';
import { HbSwitchBase } from './switch.base';
import { switchCardVariants, switchTrackVariants } from './switch.variants';

@Component({
  selector: 'hb-switch-card',
  imports: [NgIcon],
  template: `
    <label
      [class]="cardClasses()"
      [attr.data-state]="state()"
      [attr.aria-invalid]="hbInvalid() || null"
    >
      <input
        type="checkbox"
        role="switch"
        class="peer sr-only"
        [id]="hbInputId() || uid"
        [checked]="hbChecked()"
        [disabled]="isDisabled()"
        [required]="hbRequired() || null"
        [attr.name]="hbName() || null"
        [attr.aria-invalid]="hbInvalid() || null"
        [attr.aria-label]="hbAriaLabel() || null"
        (change)="onNativeChange($event)"
        (blur)="onTouched()"
      />
      <div class="flex-1"><ng-content /></div>
      @if (hbIndicator()) {
        <span [class]="trackClasses()" [attr.data-state]="state()" aria-hidden="true">
          <span [class]="thumbClasses()" [attr.data-state]="state()">
            @if (hbChecked() && hbCheckedIcon()) {
              <ng-icon [name]="hbCheckedIcon()" />
            } @else if (!hbChecked() && hbUncheckedIcon()) {
              <ng-icon [name]="hbUncheckedIcon()" />
            }
          </span>
        </span>
      }
    </label>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  providers: [
    {
      provide: NG_VALUE_ACCESSOR,
      useExisting: forwardRef(() => HbSwitchCardComponent),
      multi: true,
    },
  ],
  host: { '[class]': "'block'", '[attr.data-slot]': "'switch-card'" },
  exportAs: 'hbSwitchCard',
})
export class HbSwitchCardComponent extends HbSwitchBase {
  readonly hbIndicator = input(true, { transform: booleanAttribute });

  protected readonly cardClasses = computed(() =>
    cn(switchCardVariants({ status: this.hbStatus() }), this.class()),
  );
  protected readonly trackClasses = computed(() =>
    switchTrackVariants({ size: this.hbSize(), status: this.hbStatus(), focusable: false }),
  );
}

import {
  booleanAttribute,
  computed,
  Directive,
  input,
  model,
  output,
  signal,
} from '@angular/core';
import { type ControlValueAccessor } from '@angular/forms';

import { type ClassValue } from '{{alias}}/utils';
import {
  switchThumbVariants,
  type HbSwitchSize,
  type HbSwitchStatus,
} from './switch.variants';



let switchUid = 0;
@Directive()
export abstract class HbSwitchBase implements ControlValueAccessor {
  protected readonly uid = `hb-switch-${++switchUid}`;

  readonly hbChecked = model(false);
  readonly hbStatus = input<HbSwitchStatus>('default');
  readonly hbSize = input<HbSwitchSize>('md');
  readonly hbDisabled = input(false, { transform: booleanAttribute });
  readonly hbInvalid = input(false, { transform: booleanAttribute });
  readonly hbRequired = input(false, { transform: booleanAttribute });
  readonly hbName = input<string>('');
  readonly hbInputId = input<string>('');
  readonly hbAriaLabel = input<string>('');
  readonly hbCheckedIcon = input<string>('');
  readonly hbUncheckedIcon = input<string>('');
  readonly class = input<ClassValue>('');

  readonly hbChange = output<boolean>();

  protected readonly cvaDisabled = signal(false);

  protected readonly isDisabled = computed(() => this.hbDisabled() || this.cvaDisabled());
  protected readonly state = computed(() => (this.hbChecked() ? 'checked' : 'unchecked'));
  protected readonly thumbClasses = computed(() => switchThumbVariants({ size: this.hbSize() }));

  protected onNativeChange(event: Event): void {
    const next = (event.target as HTMLInputElement).checked;
    this.hbChecked.set(next);
    this.onChange(next);
    this.onTouched();
    this.hbChange.emit(next);
  }

  protected onChange: (value: boolean) => void = () => {};
  protected onTouched: () => void = () => {};
  writeValue(value: boolean): void {
    this.hbChecked.set(!!value);
  }
  registerOnChange(fn: (value: boolean) => void): void {
    this.onChange = fn;
  }
  registerOnTouched(fn: () => void): void {
    this.onTouched = fn;
  }
  setDisabledState(isDisabled: boolean): void {
    this.cvaDisabled.set(isDisabled);
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  forwardRef,
  input,
  ViewEncapsulation,
} from '@angular/core';
import { NG_VALUE_ACCESSOR } from '@angular/forms';
import { NgIcon } from '@ng-icons/core';

import { cn } from '{{alias}}/utils';
import { HbSwitchBase } from './switch.base';
import { switchTrackVariants, type HbSwitchLabelPosition } from './switch.variants';

@Component({
  selector: 'hb-switch',
  imports: [NgIcon],
  template: `
    <label [class]="labelClasses()">
      <input
        type="checkbox"
        role="switch"
        class="peer sr-only"
        [id]="hbInputId() || uid"
        [checked]="hbChecked()"
        [disabled]="isDisabled()"
        [required]="hbRequired() || null"
        [attr.name]="hbName() || null"
        [attr.aria-invalid]="hbInvalid() || null"
        [attr.aria-label]="hbAriaLabel() || null"
        (change)="onNativeChange($event)"
        (blur)="onTouched()"
      />
      <span
        [class]="trackClasses()"
        [attr.data-state]="state()"
        [attr.aria-invalid]="hbInvalid() || null"
        aria-hidden="true"
      >
        <span [class]="thumbClasses()" [attr.data-state]="state()">
          @if (hbChecked() && hbCheckedIcon()) {
            <ng-icon [name]="hbCheckedIcon()" />
          } @else if (!hbChecked() && hbUncheckedIcon()) {
            <ng-icon [name]="hbUncheckedIcon()" />
          }
        </span>
      </span>
      <ng-content />
    </label>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  providers: [
    { provide: NG_VALUE_ACCESSOR, useExisting: forwardRef(() => HbSwitchComponent), multi: true },
  ],
  host: { '[class]': "'inline-flex'", '[attr.data-slot]': "'switch'" },
  exportAs: 'hbSwitch',
})
export class HbSwitchComponent extends HbSwitchBase {
  readonly hbLabelPosition = input<HbSwitchLabelPosition>('end');

  protected readonly trackClasses = computed(() =>
    cn(
      switchTrackVariants({ size: this.hbSize(), status: this.hbStatus(), focusable: true }),
      this.class(),
    ),
  );
  protected readonly labelClasses = computed(() =>
    cn(
      'relative inline-flex items-center gap-2 text-sm leading-none select-none',
      this.hbLabelPosition() === 'start' && 'flex-row-reverse',
      this.isDisabled() ? 'cursor-not-allowed opacity-70' : 'cursor-pointer',
    ),
  );
}

import { HbSwitchCardComponent } from './switch-card.component';
import { HbSwitchComponent } from './switch.component';

export const HbSwitchImports = [HbSwitchComponent, HbSwitchCardComponent] as const;

import { cva, type VariantProps } from 'class-variance-authority';

import { cn } from '{{alias}}/utils';

export const switchTrackVariants = cva(
  'relative inline-flex shrink-0 cursor-pointer items-center rounded-full border border-transparent px-0.5 outline-none transition-colors data-[state=unchecked]:bg-input',
  {
    variants: {
      size: {
        xs: 'h-4 w-7',
        sm: 'h-5 w-9',
        md: 'h-6 w-11',
        lg: 'h-7 w-13',
        xl: 'h-8 w-15',
      },
      status: {
        default: 'data-[state=checked]:bg-primary',
        error: 'data-[state=checked]:bg-destructive',
        success: 'data-[state=checked]:bg-success',
        warning: 'data-[state=checked]:bg-warning',
      },
      focusable: {
        true: cn(
          'peer-focus-visible:border-ring peer-focus-visible:ring-[3px] peer-focus-visible:ring-ring/50',
          'peer-disabled:cursor-not-allowed peer-disabled:opacity-50',
          'aria-[invalid=true]:border-destructive aria-[invalid=true]:ring-destructive/20',
        ),
        false: '',
      },
    },
    defaultVariants: { size: 'md', status: 'default', focusable: true },
  },
);

export const switchThumbVariants = cva(
  'pointer-events-none grid place-content-center rounded-full bg-background text-foreground shadow-sm ring-0 transition-transform data-[state=unchecked]:translate-x-0',
  {
    variants: {
      size: {
        xs: 'size-3 [&_svg]:size-2 data-[state=checked]:translate-x-3',
        sm: 'size-4 [&_svg]:size-2.5 data-[state=checked]:translate-x-4',
        md: 'size-5 [&_svg]:size-3 data-[state=checked]:translate-x-5',
        lg: 'size-6 [&_svg]:size-3.5 data-[state=checked]:translate-x-6',
        xl: 'size-7 [&_svg]:size-4 data-[state=checked]:translate-x-7',
      },
    },
    defaultVariants: { size: 'md' },
  },
);

export const switchCardVariants = cva(
  cn(
    'relative flex w-full cursor-pointer items-center gap-3 rounded-md border border-input bg-background p-4 text-left text-sm shadow-xs transition-[color,box-shadow]',
    'has-[:focus-visible]:border-ring has-[:focus-visible]:ring-[3px] has-[:focus-visible]:ring-ring/50',
    'has-[:disabled]:cursor-not-allowed has-[:disabled]:opacity-50',
    'data-[state=checked]:ring-1',
    'aria-[invalid=true]:border-destructive',
  ),
  {
    variants: {
      status: {
        default:
          'data-[state=checked]:border-primary data-[state=checked]:ring-primary data-[state=checked]:bg-primary/5',
        error:
          'data-[state=checked]:border-destructive data-[state=checked]:ring-destructive data-[state=checked]:bg-destructive/5',
        success:
          'data-[state=checked]:border-success data-[state=checked]:ring-success data-[state=checked]:bg-success/5',
        warning:
          'data-[state=checked]:border-warning data-[state=checked]:ring-warning data-[state=checked]:bg-warning/5',
      },
    },
    defaultVariants: { status: 'default' },
  },
);

export type HbSwitchSize = NonNullable<VariantProps<typeof switchThumbVariants>['size']>;
export type HbSwitchStatus = NonNullable<VariantProps<typeof switchTrackVariants>['status']>;
export type HbSwitchLabelPosition = 'start' | 'end';

